mapper.select:
SELECT * FROM (
SELECT t.id AS id, t.id AS task_id, 'task' AS task_type, 0 AS is_shadow, NULL::BIGINT AS source_task_id, NULL::BIGINT AS source_project_id, NULL::VARCHAR AS source_task_name, NULL::VARCHAR AS source_project_name, NULL::VARCHAR AS source_description, NULL::VARCHAR AS shadow_alias, NULL::VARCHAR AS shadow_description, t.task_name, t.description, t.progress, t.status, t.priority, t.start_date, t.end_date, t.end_date AS due_date, t.assignee_id AS assignee, t.assignee_id AS owner_id, e.employee_name AS assignee_name, e.employee_name AS owner_name, t.project_id, p.project_name, t.is_pinned, t.is_focus, t.parent_id, t.task_code, NULL::VARCHAR AS task_module, t.attachments, t.stakeholders, t.create_time, t.update_time, lpu.last_progress_update_time, t.create_by::VARCHAR AS created_by, ce.employee_name AS created_by_name, t.create_time AS created_at, t.update_time AS updated_at, 0 AS annotation_count, 0 AS task_type_order FROM pm_task t LEFT JOIN pm_project p ON t.project_id = p.id LEFT JOIN sys_employee e ON t.assignee_id = e.id LEFT JOIN sys_employee ce ON t.create_by = ce.id LEFT JOIN LATERAL ( SELECT MAX(create_time) AS last_progress_update_time FROM pm_task_progress_update WHERE task_id = t.id ) lpu ON TRUE WHERE t.project_id = #{projectId} AND (t.parent_id IS NULL OR t.parent_id = 0)
AND t.task_name ILIKE CONCAT('%', #{taskName}, '%')
AND t.status = #{status}
AND t.priority = #{priority}
AND t.assignee_id = #{assigneeId}
AND e.employee_name ILIKE CONCAT('%', #{assigneeName}, '%')
UNION ALL
SELECT s.id AS id, NULL::BIGINT AS task_id, 'shadow' AS task_type, 1 AS is_shadow, s.source_task_id, st.project_id AS source_project_id, st.task_name AS source_task_name, sp.project_name AS source_project_name, st.description AS source_description, s.shadow_alias, s.shadow_description, COALESCE(s.shadow_alias, st.task_name) AS task_name, st.description AS description, st.progress, st.status, st.priority, st.start_date, st.end_date, st.end_date AS due_date, st.assignee_id AS assignee, st.assignee_id AS owner_id, e.employee_name AS assignee_name, e.employee_name AS owner_name, s.project_id, p.project_name, 0 AS is_pinned, 0 AS is_focus, s.parent_id, NULL::VARCHAR AS task_code, NULL::VARCHAR AS task_module, st.attachments AS attachments, st.stakeholders AS stakeholders, s.created_at AS create_time, s.updated_at AS update_time, lpu.last_progress_update_time, s.created_by, ce.employee_name AS created_by_name, s.created_at, s.updated_at, COALESCE(la.annotation_count, 0) AS annotation_count, 1 AS task_type_order FROM pm_task_shadow s INNER JOIN pm_task st ON s.source_task_id = st.id LEFT JOIN pm_project p ON s.project_id = p.id LEFT JOIN pm_project sp ON st.project_id = sp.id LEFT JOIN sys_employee e ON st.assignee_id = e.id LEFT JOIN sys_employee ce ON s.created_by = ce.username LEFT JOIN LATERAL ( SELECT MAX(create_time) AS last_progress_update_time FROM pm_task_progress_update WHERE task_id = s.source_task_id ) lpu ON TRUE LEFT JOIN LATERAL ( SELECT COUNT(*) AS annotation_count FROM pm_shadow_annotation WHERE shadow_id = s.id ) la ON TRUE WHERE s.project_id = #{projectId} AND (s.parent_id IS NULL OR s.parent_id = 0)
AND COALESCE(s.shadow_alias, st.task_name) ILIKE CONCAT('%', #{taskName}, '%')
AND st.status = #{status}
AND st.priority = #{priority}
AND st.assignee_id = #{assigneeId}
AND e.employee_name ILIKE CONCAT('%', #{assigneeName}, '%')
) AS combined
ORDER BY task_type_order, is_pinned DESC, CASE WHEN status IN (1, 2) THEN 0 WHEN status = 3 THEN 1 WHEN status = 4 THEN 2 ELSE 3 END, create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT (

    SELECT COUNT(*)
    FROM pm_task t
    LEFT JOIN sys_employee e ON t.assignee_id = e.id
    WHERE t.project_id = #{projectId}
      AND (t.parent_id IS NULL OR t.parent_id = 0)

      AND t.task_name ILIKE CONCAT('%', #{taskName}, '%')

     AND t.status = #{status}
     AND t.priority = #{priority}
     AND t.assignee_id = #{assigneeId}

      AND e.employee_name ILIKE CONCAT('%', #{assigneeName}, '%')

) + (

    SELECT COUNT(*)
    FROM pm_task_shadow s
    INNER JOIN pm_task st ON s.source_task_id = st.id
    LEFT JOIN sys_employee e ON st.assignee_id = e.id
    WHERE s.project_id = #{projectId}
      AND (s.parent_id IS NULL OR s.parent_id = 0)

      AND COALESCE(s.shadow_alias, st.task_name) ILIKE CONCAT('%', #{taskName}, '%')

     AND st.status = #{status}
     AND st.priority = #{priority}
     AND st.assignee_id = #{assigneeId}

      AND e.employee_name ILIKE CONCAT('%', #{assigneeName}, '%')

) AS total_count

SELECT * FROM (
SELECT t.id AS id, t.id AS task_id, 'task' AS task_type, 0 AS is_shadow, NULL::BIGINT AS source_task_id, NULL::BIGINT AS source_project_id, NULL::VARCHAR AS source_task_name, NULL::VARCHAR AS source_project_name, NULL::VARCHAR AS source_description, NULL::VARCHAR AS shadow_alias, NULL::VARCHAR AS shadow_description, t.task_name, t.description, t.progress, t.status, t.priority, t.start_date, t.end_date, t.end_date AS due_date, t.assignee_id AS assignee, t.assignee_id AS owner_id, e.employee_name AS assignee_name, e.employee_name AS owner_name, t.project_id, p.project_name, t.is_pinned, t.is_focus, t.parent_id, t.task_code, NULL::VARCHAR AS task_module, t.attachments, t.stakeholders, t.create_time, t.update_time, lpu.last_progress_update_time, t.create_by::VARCHAR AS created_by, ce.employee_name AS created_by_name, t.create_time AS created_at, t.update_time AS updated_at, 0 AS annotation_count, 0 AS task_type_order FROM pm_task t LEFT JOIN pm_project p ON t.project_id = p.id LEFT JOIN sys_employee e ON t.assignee_id = e.id LEFT JOIN sys_employee ce ON t.create_by = ce.id LEFT JOIN LATERAL ( SELECT MAX(create_time) AS last_progress_update_time FROM pm_task_progress_update WHERE task_id = t.id ) lpu ON TRUE WHERE t.project_id = #{projectId} AND t.parent_id IN
#{rid}
UNION ALL
SELECT s.id AS id, NULL::BIGINT AS task_id, 'shadow' AS task_type, 1 AS is_shadow, s.source_task_id, st.project_id AS source_project_id, st.task_name AS source_task_name, sp.project_name AS source_project_name, st.description AS source_description, s.shadow_alias, s.shadow_description, COALESCE(s.shadow_alias, st.task_name) AS task_name, st.description AS description, st.progress, st.status, st.priority, st.start_date, st.end_date, st.end_date AS due_date, st.assignee_id AS assignee, st.assignee_id AS owner_id, e.employee_name AS assignee_name, e.employee_name AS owner_name, s.project_id, p.project_name, 0 AS is_pinned, 0 AS is_focus, s.parent_id, NULL::VARCHAR AS task_code, NULL::VARCHAR AS task_module, st.attachments AS attachments, st.stakeholders AS stakeholders, s.created_at AS create_time, s.updated_at AS update_time, lpu.last_progress_update_time, s.created_by, ce.employee_name AS created_by_name, s.created_at, s.updated_at, COALESCE(la.annotation_count, 0) AS annotation_count, 1 AS task_type_order FROM pm_task_shadow s INNER JOIN pm_task st ON s.source_task_id = st.id LEFT JOIN pm_project p ON s.project_id = p.id LEFT JOIN pm_project sp ON st.project_id = sp.id LEFT JOIN sys_employee e ON st.assignee_id = e.id LEFT JOIN sys_employee ce ON s.created_by = ce.username LEFT JOIN LATERAL ( SELECT MAX(create_time) AS last_progress_update_time FROM pm_task_progress_update WHERE task_id = s.source_task_id ) lpu ON TRUE LEFT JOIN LATERAL ( SELECT COUNT(*) AS annotation_count FROM pm_shadow_annotation WHERE shadow_id = s.id ) la ON TRUE WHERE s.project_id = #{projectId} AND s.parent_id IN
#{rid}
) AS combined
ORDER BY create_time DESC
